export function renderNav(activePage) {
  // Inject CSS
  if (!document.getElementById('magi-nav-styles')) {
    const style = document.createElement('style');
    style.id = 'magi-nav-styles';
    style.textContent = NAV_CSS;
    document.head.appendChild(style);
  }

  // Build nav HTML
  const nav = document.createElement('nav');
  nav.className = 'magi-nav';
  nav.id = 'magiNav';

  let html = `<a class="magi-nav-logo" href="/dashboard/">
    <span class="magi-nav-logo-icon">✦</span>
    <span class="magi-nav-logo-text">MAGI</span>
  </a>
  <div class="magi-nav-scroll">`;

  for (const group of NAV_GROUPS) {
    html += `<div class="magi-nav-group-label">${group.label}</div>`;
    for (const item of group.items) {
      const isActive = activePage === item.id ? ' active' : '';
      html += `<a class="magi-nav-item${isActive}" href="${item.path}">
        <span class="magi-nav-item-icon">${item.icon}</span>
        <span class="magi-nav-item-label">${item.label}</span>
      </a>`;
    }
  }

  html += '</div>';
  nav.innerHTML = html;

  // Create hamburger button
  const burger = document.createElement('button');
  burger.className = 'magi-nav-hamburger';
  burger.id = 'magiNavBurger';
  burger.innerHTML = '☰';
  burger.setAttribute('aria-label', 'Toggle navigation');

  // Create overlay
  const overlay = document.createElement('div');
  overlay.className = 'magi-nav-overlay';
  overlay.id = 'magiNavOverlay';

  // Inject into DOM
  const target = document.getElementById('nav');
  if (target) {
    target.appendChild(nav);
    target.appendChild(burger);
    target.appendChild(overlay);
  } else {
    document.body.prepend(overlay);
    document.body.prepend(nav);
    document.body.prepend(burger);
  }

  // Mobile toggle
  function toggleMobileNav() {
    const open = nav.classList.toggle('mobile-open');
    overlay.classList.toggle('show', open);
  }
  burger.addEventListener('click', toggleMobileNav);
  overlay.addEventListener('click', toggleMobileNav);

  return nav;
}

/**
 * MAGI Markdown Renderer — Safe, XSS-protected
 * ES Module: import { renderMarkdown } from '/shared/markdown.js';
 *
 * Uses /shared/marked.min.js + /shared/highlight.min.js
 * Both must be loaded before this module, OR this loads them dynamically.
 */

// ── XSS Sanitizer ──

const ALLOWED_TAGS = new Set([
  'p', 'br', 'strong', 'b', 'em', 'i', 'u', 's', 'del', 'ins',
  'h1', 'h2', 'h3', 'h4', 'h5', 'h6',
  'ul', 'ol', 'li', 'blockquote', 'hr',
  'pre', 'code', 'span',
  'table', 'thead', 'tbody', 'tr', 'th', 'td',
  'a', 'img',
  'div', 'sup', 'sub', 'details', 'summary',
]);

const ALLOWED_ATTRS = {
  a: new Set(['href', 'title', 'target', 'rel']),
  img: new Set(['src', 'alt', 'title', 'width', 'height']),
  td: new Set(['align']),
  th: new Set(['align']),
  code: new Set(['class']),
  span: new Set(['class']),
  pre: new Set(['class']),
  div: new Set(['class']),
};

function sanitizeHtml(html) {
  const doc = new DOMParser().parseFromString(html, 'text/html');
  sanitizeNode(doc.body);
  return doc.body.innerHTML;
}

function sanitizeNode(node) {
  const children = Array.from(node.childNodes);
  for (const child of children) {
    if (child.nodeType === Node.TEXT_NODE) continue;
    if (child.nodeType === Node.COMMENT_NODE) {
      child.remove();
      continue;
    }
    if (child.nodeType !== Node.ELEMENT_NODE) {
      child.remove();
      continue;
    }

    const tag = child.tagName.toLowerCase();

    // Script / style / iframe / etc — kill
    if (!ALLOWED_TAGS.has(tag)) {
      // Keep text content, remove the element itself
      const fragment = document.createDocumentFragment();
      while (child.firstChild) fragment.appendChild(child.firstChild);
      child.replaceWith(fragment);
      continue;
    }

    // Strip disallowed attributes
    const allowed = ALLOWED_ATTRS[tag] || new Set();
    const attrs = Array.from(child.attributes);
    for (const attr of attrs) {
      if (!allowed.has(attr.name)) {
        child.removeAttribute(attr.name);
        continue;
      }
      // Sanitize href/src for javascript: protocol
      if (attr.name === 'href' || attr.name === 'src') {
        const val = attr.value.trim().toLowerCase();
        if (val.startsWith('javascript:') || val.startsWith('data:text/html')) {
          child.removeAttribute(attr.name);
        }
      }
    }

    // Force safe link attributes
    if (tag === 'a') {
      child.setAttribute('target', '_blank');
      child.setAttribute('rel', 'noopener noreferrer');
    }

    sanitizeNode(child);
  }
}

// ── Markdown Renderer ──

let _markedReady = false;
let _hlReady = false;

function ensureLibs() {
  if (typeof marked !== 'undefined') {
    _markedReady = true;
    try {
      marked.use({ gfm: true, breaks: true });
    } catch { /* already configured */ }
  }
  if (typeof hljs !== 'undefined') _hlReady = true;
}

export function renderMarkdown(text) {
  if (!text) return '';
  ensureLibs();

  if (!_markedReady) {
    // Fallback: return escaped text with basic formatting
    return escapeBasic(text);
  }

  try {
    // Parse markdown
    let html = marked.parse(text);

    // Sanitize output
    html = sanitizeHtml(html);

    // Apply syntax highlighting to code blocks
    if (_hlReady) {
      const tmp = document.createElement('div');
      tmp.innerHTML = html;
      tmp.querySelectorAll('pre code').forEach((block) => {
        try { hljs.highlightElement(block); } catch { /* skip */ }
      });
      html = tmp.innerHTML;
    }

    return html;
  } catch (e) {
    console.error('[MAGI MD]', e);
    return escapeBasic(text);
  }
}

function escapeBasic(text) {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\n/g, '<br>');
}

/**
 * Convenience: render markdown into a DOM element
 * Also adds copy buttons to code blocks
 */
export function renderMarkdownInto(element, text) {
  if (!element) return;
  element.innerHTML = renderMarkdown(text);

  // Add copy buttons to code blocks
  element.querySelectorAll('pre').forEach((pre) => {
    pre.style.position = 'relative';
    const btn = document.createElement('button');
    btn.textContent = 'Copy';
    btn.style.cssText = 'position:absolute;top:6px;right:6px;padding:2px 8px;font-size:9px;border-radius:4px;border:1px solid rgba(255,255,255,0.05);background:rgba(0,0,0,0.5);color:var(--text-tertiary,#5a6478);cursor:pointer;font-family:inherit;opacity:0;transition:opacity 0.15s';
    btn.onmouseenter = () => { btn.style.color = 'var(--text-primary,#e8edf5)'; btn.style.borderColor = 'rgba(255,255,255,0.1)'; };
    btn.onmouseleave = () => { btn.style.color = ''; btn.style.borderColor = ''; };
    btn.onclick = () => {
      navigator.clipboard.writeText(pre.textContent.replace(/Copy$/, '')).then(() => {
        btn.textContent = '✓';
        setTimeout(() => { btn.textContent = 'Copy'; }, 1500);
      });
    };
    pre.addEventListener('mouseenter', () => { btn.style.opacity = '1'; });
    pre.addEventListener('mouseleave', () => { btn.style.opacity = '0'; });
    pre.appendChild(btn);
  });
}

/**
 * MAGI WebSocket Manager
 * ES Module: import { WSManager } from '/shared/ws-manager.js';
 */

const DEFAULT_OPTIONS = {
  maxRetries: 20,
  heartbeatInterval: 30000,   // 30s ping
  reconnectBase: 1000,        // 1s initial
  reconnectMax: 30000,        // 30s max
};

export class WSManager {
  constructor(url, options = {}) {
    this._url = url;
    this._opts = { ...DEFAULT_OPTIONS, ...options };
    this._ws = null;
    this._listeners = {};
    this._retries = 0;
    this._heartbeatTimer = null;
    this._reconnectTimer = null;
    this._intentionalClose = false;
    this._indicator = null;
  }

  // ── Public API ──

  connect() {
    this._intentionalClose = false;
    this._doConnect();
    return this;
  }

  disconnect() {
    this._intentionalClose = true;
    this._cleanup();
    if (this._ws) {
      this._ws.close(1000, 'Client disconnect');
      this._ws = null;
    }
    this._setIndicator('offline');
  }

  send(data) {
    if (this._ws?.readyState === WebSocket.OPEN) {
      this._ws.send(typeof data === 'string' ? data : JSON.stringify(data));
      return true;
    }
    return false;
  }

  on(event, handler) {
    if (!this._listeners[event]) this._listeners[event] = [];
    this._listeners[event].push(handler);
    return this;
  }

  off(event, handler) {
    const arr = this._listeners[event];
    if (!arr) return this;
    this._listeners[event] = arr.filter(h => h !== handler);
    return this;
  }

  get state() {
    if (!this._ws) return 'disconnected';
    switch (this._ws.readyState) {
      case WebSocket.CONNECTING: return 'connecting';
      case WebSocket.OPEN: return 'connected';
      case WebSocket.CLOSING: return 'closing';
      case WebSocket.CLOSED: return 'disconnected';
      default: return 'unknown';
    }
  }

  // ── Internal ──

  _emit(event, data) {
    const arr = this._listeners[event];
    if (arr) arr.forEach(fn => { try { fn(data); } catch (e) { console.error('[WS]', e); } });
  }

  _doConnect() {
    this._cleanup();
    this._setIndicator('connecting');

    try {
      this._ws = new WebSocket(this._url);
    } catch (e) {
      this._scheduleReconnect();
      return;
    }

    this._ws.onopen = () => {
      this._retries = 0;
      this._setIndicator('connected');
      this._startHeartbeat();
      this._emit('open');
    };

    this._ws.onclose = (e) => {
      this._cleanup();
      this._setIndicator('offline');
      this._emit('close', e);
      if (!this._intentionalClose) {
        this._scheduleReconnect();
      }
    };

    this._ws.onerror = (e) => {
      this._emit('error', e);
      // onclose will fire after onerror, so reconnect logic is there
      this._ws.close();
    };

    this._ws.onmessage = (e) => {
      let data;
      try { data = JSON.parse(e.data); } catch { data = e.data; }

      // Handle server ping
      if (data?.type === 'ping') {
        this.send({ type: 'pong' });
        return;
      }

      this._emit('message', data);
    };
  }

  _scheduleReconnect() {
    if (this._intentionalClose) return;

    this._retries++;
    if (this._retries > this._opts.maxRetries) {
      this._setIndicator('offline');
      this._emit('max-retries', this._retries);
      return;
    }

    // Exponential backoff with jitter
    const delay = Math.min(
      this._opts.reconnectBase * Math.pow(2, this._retries - 1) + Math.random() * 500,
      this._opts.reconnectMax
    );

    this._setIndicator('reconnecting');
    this._emit('reconnecting', { attempt: this._retries, delay });

    this._reconnectTimer = setTimeout(() => this._doConnect(), delay);
  }

  _startHeartbeat() {
    this._stopHeartbeat();
    this._heartbeatTimer = setInterval(() => {
      if (this._ws?.readyState === WebSocket.OPEN) {
        this.send({ type: 'ping' });
      }
    }, this._opts.heartbeatInterval);
  }

  _stopHeartbeat() {
    if (this._heartbeatTimer) {
      clearInterval(this._heartbeatTimer);
      this._heartbeatTimer = null;
    }
  }

  _cleanup() {
    this._stopHeartbeat();
    if (this._reconnectTimer) {
      clearTimeout(this._reconnectTimer);
      this._reconnectTimer = null;
    }
  }

  // ── Visual Indicator ──

  _setIndicator(state) {
    // state: 'connected' | 'connecting' | 'reconnecting' | 'offline'
    if (!this._indicator) {
      this._indicator = document.getElementById('ws-indicator');
    }
    if (!this._indicator) return;

    const dot = this._indicator.querySelector('.ws-dot') || this._indicator;

    dot.classList.remove('ws-connected', 'ws-connecting', 'ws-reconnecting', 'ws-offline');
    dot.classList.add(`ws-${state}`);

    const label = this._indicator.querySelector('.ws-label');
    if (label) {
      const labels = {
        connected: 'Online',
        connecting: 'Connecting',
        reconnecting: 'Reconnecting',
        offline: 'Offline'
      };
      label.textContent = labels[state] || state;
    }
  }
}

